import{c as o,Q as n,j as a,m as s}from"./chunks/framework.CBiVa4O3.js";const c=JSON.parse('{"title":"OWASP Top 10 2025:现代版重排、风险打分、怎么读这份清单","description":"","frontmatter":{},"headers":[],"relativePath":"../securityLearning/09-OWASP-Top10.md","filePath":"../securityLearning/09-OWASP-Top10.md","lastUpdated":1778496697000}'),r={name:"../securityLearning/09-OWASP-Top10.md"};function e(i,t,l,u,g,p){return n(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="owasp-top-10-2025-现代版重排、风险打分、怎么读这份清单" tabindex="-1">OWASP Top 10 2025:现代版重排、风险打分、怎么读这份清单 <a class="header-anchor" href="#owasp-top-10-2025-现代版重排、风险打分、怎么读这份清单" aria-label="Permalink to &quot;OWASP Top 10 2025:现代版重排、风险打分、怎么读这份清单&quot;">​</a></h1><p>很多工程师对 OWASP Top 10 的第一印象是「<strong>安全圈的十大金曲榜</strong>」——隔几年发一次,前十位会换,大家拿来背一背、应付一下面试和合规审计。<strong>这个看法是错的,而且错得很有代价</strong>。OWASP Top 10 既不是「最严重的十个漏洞」,也不是「最常见的十类 bug」,<strong>它是「全球安全行业对 Web 风险的一次结构化共识投票」</strong>——选什么、不选什么、怎么排序,每一条背后都有数据 + 争议 + 行业偏好。<strong>看懂了这份清单怎么&quot;做出来&quot;,你才看得懂它&quot;想让你做什么&quot;</strong>。</p><blockquote><p>一句话先记住:<strong>OWASP Top 10 ≠ 漏洞排行榜,而是「行业认知地图」</strong>——它告诉你&quot;现在大家普遍承认这十类风险值得专门投资源去防&quot;,<strong>排名是&quot;频率 + 可利用性 + 影响 + 行业感知&quot;四个权重的加权结果</strong>,所以<strong>理解打分逻辑</strong>比背名字重要 100 倍。<strong>2021 版的最大变化是引入了&quot;设计类风险&quot;(A04)和&quot;供应链类风险&quot;(A08),2025 版预计会把 AI/Agent 滥用和 IaC 错配的权重再往上推</strong>——这两条变化背后,是整个行业对&quot;漏洞从哪儿来&quot;的认知在迭代。</p></blockquote><p>webLearning/35 用一节浅讲过 OWASP Top 10 的名字和一句话定义。<strong>这一篇是深度版</strong>——讲清楚这份清单是怎么投出来的、为什么这么排、2025 会怎么变、以及<strong>怎么把它变成你团队上线前的硬性 checklist</strong>。后面 10-15 篇会逐项展开 XSS、CSRF、注入、SSRF、反序列化、认证授权——<strong>这篇是那 6 篇的总图,先看完这张图,后面每一篇才能放到正确的位置</strong>。</p><hr><h2 id="一、owasp-top-10-到底是什么" tabindex="-1">一、OWASP Top 10 到底是什么 <a class="header-anchor" href="#一、owasp-top-10-到底是什么" aria-label="Permalink to &quot;一、OWASP Top 10 到底是什么&quot;">​</a></h2><h3 id="_1-1-三个常见的误解" tabindex="-1">1.1 三个常见的误解 <a class="header-anchor" href="#_1-1-三个常见的误解" aria-label="Permalink to &quot;1.1 三个常见的误解&quot;">​</a></h3><p><strong>误解 1:Top 10 = 最严重的 10 个漏洞</strong></p><p>不是。如果按&quot;单次利用最严重&quot;,远程代码执行(RCE)、零日漏洞、内存破坏类才是天花板,<strong>但它们从来没排在 OWASP Top 10 第一</strong>。A01 Broken Access Control 排第一,<strong>是因为它在&quot;实际项目里出现得最普遍&quot;</strong>——大部分公司一抽查就能挑出权限错配,而 RCE 是少数。</p><p><strong>误解 2:Top 10 = 完整的 Web 安全清单</strong></p><p>也不是。Top 10 是<strong>主动忽略</strong>了很多&quot;细分但重要&quot;的类别——DoS、信息泄漏、缓存投毒、HTTP 走私、原型链污染——这些都没单列。<strong>Top 10 是粗粒度的&quot;风险大类&quot;</strong>,每一类下面再细分能拆出几十个子项。<strong>真正完整的清单是 OWASP ASVS(Application Security Verification Standard),Top 10 只是 ASVS 的&quot;科普版&quot;</strong>。</p><p><strong>误解 3:Top 10 是给开发者看的</strong></p><p><strong>只对了一半</strong>。Top 10 真正的受众是<strong>决策层</strong>——CTO / CISO / 安全负责人——给他们一个&quot;今年应该把预算投在哪儿&quot;的共识。开发者直接看 Top 10 信息密度太低,<strong>应该看 OWASP Cheat Sheet 系列或 ASVS</strong>。但 Top 10 是<strong>所有甲方安全评审、合规审计、招投标安全条款</strong>的最低公约数,工程师必须懂它的语义。</p><h3 id="_1-2-owasp-top-10-真正的定位" tabindex="-1">1.2 OWASP Top 10 真正的定位 <a class="header-anchor" href="#_1-2-owasp-top-10-真正的定位" aria-label="Permalink to &quot;1.2 OWASP Top 10 真正的定位&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        粗 ←──────────────────────────────→ 细</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   OWASP Top 10  →  OWASP ASVS  →  Cheat Sheet  →  CWE/CVE</span></span>
<span class="line"><span>   (行业共识)       (验证清单)      (具体修复)      (单个漏洞)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   决策层           安全工程师       开发工程师       挖洞 / 修复</span></span></code></pre></div><p><strong>Top 10 的价值是&quot;统一语义&quot;</strong>——当你跟另一个团队、另一家公司、另一国监管对话时,<strong>说&quot;A01 Broken Access Control&quot;比说&quot;权限校验缺失&quot;省 5 分钟</strong>。它是行业的「<strong>Lingua Franca</strong>」。</p><hr><h2 id="二、top-10-是怎么-排-出来的" tabindex="-1">二、Top 10 是怎么&quot;排&quot;出来的 <a class="header-anchor" href="#二、top-10-是怎么-排-出来的" aria-label="Permalink to &quot;二、Top 10 是怎么&quot;排&quot;出来的&quot;">​</a></h2><p>很多人以为 OWASP 每四年开个会拍脑袋定一次,<strong>完全错了</strong>。从 2017 版开始,<strong>Top 10 是数据驱动 + 行业调研双轨制</strong>——这个流程值得每个安全工程师都知道。</p><h3 id="_2-1-数据来源-8-2-模型" tabindex="-1">2.1 数据来源:8 + 2 模型 <a class="header-anchor" href="#_2-1-数据来源-8-2-模型" aria-label="Permalink to &quot;2.1 数据来源:8 + 2 模型&quot;">​</a></h3><p><strong>2021 版的数据组成</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>8 个&quot;漏洞类别&quot;:全部来自数据</span></span>
<span class="line"><span>   ├─ 数据贡献者:超过 40 家公司(扫描器厂商、SOC、bug bounty)</span></span>
<span class="line"><span>   ├─ 样本量:50 万+ 应用,40 万+ 漏洞</span></span>
<span class="line"><span>   └─ 评估指标:出现率、可利用性、可检测性、技术影响</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2 个&quot;行业调研类别&quot;:来自社区投票</span></span>
<span class="line"><span>   ├─ Top 10 调研问卷(开发者 / 安全研究员)</span></span>
<span class="line"><span>   └─ 弥补&quot;数据看不到的新兴风险&quot;</span></span>
<span class="line"><span>       例:Insecure Design、Software Integrity Failures</span></span>
<span class="line"><span>       —— 这两个在 2021 是&quot;调研类&quot;挤进来的</span></span></code></pre></div><p><strong>关键设计</strong>:<strong>纯数据排序会&quot;滞后两年&quot;</strong>——新型攻击没积累足够的 CVE 之前,数据看不见。所以 OWASP 留了 2 个&quot;调研类&quot;slot,<strong>让行业可以提前预警</strong>——2021 把&quot;Insecure Design&quot;和&quot;Software Integrity Failures&quot;放进来,<strong>就是给供应链攻击和设计类风险铺路</strong>。事后证明这个判断对了,SolarWinds、Log4Shell、xz-utils 全部落在这两类。</p><h3 id="_2-2-打分公式" tabindex="-1">2.2 打分公式 <a class="header-anchor" href="#_2-2-打分公式" aria-label="Permalink to &quot;2.2 打分公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Top 10 排序 = 加权(</span></span>
<span class="line"><span>    出现率 (Incidence Rate),</span></span>
<span class="line"><span>    可利用性 (Exploitability),</span></span>
<span class="line"><span>    可检测性 (Detectability),</span></span>
<span class="line"><span>    技术影响 (Technical Impact)</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>但<strong>这四个权重不是固定的</strong>。2017 版偏&quot;出现率&quot;,所以 SQL 注入排第一(频率高)。2021 版改成偏&quot;业务影响&quot;,<strong>Broken Access Control 跃居第一</strong>——它出现率没那么夸张,但<strong>每一次都可能直接导致越权访问全库</strong>。</p><blockquote><p>这就是为什么 2021 版给人感觉&quot;重排了&quot;——<strong>不是漏洞变了,是行业开始更看重影响而不是频率</strong>。</p></blockquote><h3 id="_2-3-一个被严重低估的事实" tabindex="-1">2.3 一个被严重低估的事实 <a class="header-anchor" href="#_2-3-一个被严重低估的事实" aria-label="Permalink to &quot;2.3 一个被严重低估的事实&quot;">​</a></h3><p><strong>OWASP Top 10 的数据集是有偏的</strong>:</p><ul><li>数据来自<strong>愿意上报漏洞的公司</strong>——绝大多数是欧美中大型企业</li><li>数据来自<strong>已经做了扫描的应用</strong>——本身就有安全意识的团队</li><li>数据<strong>严重低估了内部业务系统、政务、IoT</strong>——这些根本不在扫描器视野里</li></ul><p><strong>所以 Top 10 反映的是&quot;成熟 SaaS 生态的风险结构&quot;,不是&quot;整个互联网的风险结构&quot;</strong>。如果你做 IoT、政务、工控,<strong>直接照搬 Top 10 会漏掉一大半真实风险</strong>。</p><hr><h2 id="三、2017-→-2021-→-2025-三代演变" tabindex="-1">三、2017 → 2021 → 2025 三代演变 <a class="header-anchor" href="#三、2017-→-2021-→-2025-三代演变" aria-label="Permalink to &quot;三、2017 → 2021 → 2025 三代演变&quot;">​</a></h2><h3 id="_3-1-三代对比表" tabindex="-1">3.1 三代对比表 <a class="header-anchor" href="#_3-1-三代对比表" aria-label="Permalink to &quot;3.1 三代对比表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>排名</th><th>2017</th><th>2021</th><th>2025(预期)</th></tr></thead><tbody><tr><td>A01</td><td>Injection</td><td><strong>Broken Access Control</strong> ↑</td><td>Broken Access Control</td></tr><tr><td>A02</td><td>Broken Authentication</td><td>Cryptographic Failures(原 Sensitive Data)</td><td>Cryptographic Failures</td></tr><tr><td>A03</td><td>Sensitive Data Exposure</td><td><strong>Injection</strong>(含 XSS)↓</td><td>Injection</td></tr><tr><td>A04</td><td>XXE</td><td><strong>Insecure Design</strong>(新)★</td><td>Insecure Design</td></tr><tr><td>A05</td><td>Broken Access Control</td><td>Security Misconfiguration</td><td>Security Misconfiguration</td></tr><tr><td>A06</td><td>Misconfiguration</td><td><strong>Vulnerable Components</strong> ↑</td><td><strong>Supply Chain Failures</strong>(并入)</td></tr><tr><td>A07</td><td>XSS(合并入 Injection)</td><td>Identification &amp; Auth Failures</td><td>Identification &amp; Auth Failures</td></tr><tr><td>A08</td><td>Insecure Deserialization</td><td><strong>Software &amp; Data Integrity</strong>(新)★</td><td>Software &amp; Data Integrity</td></tr><tr><td>A09</td><td>Vulnerable Components</td><td>Security Logging &amp; Monitoring Failures</td><td><strong>Logging / Detection Failures</strong>(细化)</td></tr><tr><td>A10</td><td>Insufficient Logging</td><td><strong>SSRF</strong>(新)★</td><td>SSRF / <strong>AI &amp; Agent Misuse</strong>(预期)</td></tr></tbody></table><blockquote><p>加粗 = 当年新增或位次大幅变动。★ = 通过&quot;调研类&quot;塞进来的&quot;预警型&quot;类别。</p></blockquote><h3 id="_3-2-2021-版的三个关键判断" tabindex="-1">3.2 2021 版的三个关键判断 <a class="header-anchor" href="#_3-2-2021-版的三个关键判断" aria-label="Permalink to &quot;3.2 2021 版的三个关键判断&quot;">​</a></h3><p><strong>判断 1:Broken Access Control 排第一</strong></p><p>权限校验是一个<strong>纯业务逻辑问题</strong>,框架管不到,SAST 扫不出,只能靠 code review。<strong>所以它在每个项目都会出现,而且每次出现都是&quot;越权全库&quot;级影响</strong>。OWASP 把它从 A05 抬到 A01,<strong>就是承认&quot;今天 Web 安全的最大问题已经不是注入,而是业务逻辑&quot;</strong>。</p><p><strong>判断 2:Injection 合并 XSS,降到 A03</strong></p><p>XSS 在 2017 之前一直独立排名。<strong>但现代框架(React / Vue / Angular)默认转义</strong>,XSS 的&quot;出现率&quot;大幅下降。同时 SQL 注入因为 ORM 普及,<strong>也没那么常见了</strong>。所以 OWASP 把它俩<strong>合并成&quot;注入&quot;大类</strong>,统一降级。</p><p><strong>判断 3:新增三个&quot;调研类&quot;前瞻类别</strong></p><ul><li><strong>A04 Insecure Design</strong>:承认&quot;很多漏洞不是 bug,是设计就错了&quot;——比如忘记设计速率限制、忘了考虑滥用场景</li><li><strong>A08 Software &amp; Data Integrity</strong>:承认&quot;供应链攻击是新常态&quot;——SolarWinds 之后必须有这一类</li><li><strong>A10 SSRF</strong>:承认&quot;云时代 SSRF 危害指数级放大&quot;——一旦打到云元数据接口直接接管账号</li></ul><h3 id="_3-3-2025-预期-三条演化主轴" tabindex="-1">3.3 2025 预期:三条演化主轴 <a class="header-anchor" href="#_3-3-2025-预期-三条演化主轴" aria-label="Permalink to &quot;3.3 2025 预期:三条演化主轴&quot;">​</a></h3><p>OWASP 在 2025 还没正式发布 Top 10(撰文时为 2026 年 5 月,2025 版征求意见已开始),<strong>但行业共识相当一致</strong>,大致三个方向:</p><p><strong>主轴 1:供应链类别会&quot;扩容&quot;</strong></p><p>A06 Vulnerable Components + A08 Software &amp; Data Integrity 很可能<strong>合并或并列</strong>成&quot;<strong>Supply Chain Failures</strong>&quot;。理由:Log4Shell、xz-utils、npm 投毒、PyPI typo-squat、CI/CD 凭据泄漏——<strong>这些事件用&quot;组件漏洞&quot;和&quot;完整性&quot;两个标签分开讲,已经分不清</strong>。</p><p><strong>主轴 2:AI / LLM / Agent 滥用进入清单</strong></p><p>OWASP 已经发布了独立的 <strong>OWASP Top 10 for LLM Applications</strong>(LLM01-10),覆盖 Prompt 注入、训练数据投毒、过度代理(Excessive Agency)、不安全的输出处理等。<strong>2025 主榜会不会&quot;挤进&quot;一个 AI 类别</strong>还在争论中——<strong>乐观估计是 A10 位置出现 &quot;Insecure LLM Integration&quot; 或 &quot;AI/Agent Misuse&quot;</strong>。</p><p><strong>主轴 3:Misconfiguration 会&quot;细化&quot;</strong></p><p>A05 Security Misconfiguration 在云原生时代爆炸——K8s YAML 错配、IAM 策略过宽、S3 bucket 公开、Terraform 默认值——OWASP 2025 可能把它拆出独立的&quot;<strong>IaC / Cloud Misconfiguration</strong>&quot;类别。</p><blockquote><p>这三条主轴的共性是:<strong>Web 安全的边界在外扩</strong>。原来 Top 10 只盯应用代码,现在不得不盯<strong>代码以外的东西</strong>——依赖、CI、模型、配置。<strong>安全工程师的工作范围在过去 5 年扩了 3 倍</strong>,Top 10 的演化只是这个事实的镜像。</p></blockquote><hr><h2 id="四、2021-版逐项总览-深度版" tabindex="-1">四、2021 版逐项总览(深度版) <a class="header-anchor" href="#四、2021-版逐项总览-深度版" aria-label="Permalink to &quot;四、2021 版逐项总览(深度版)&quot;">​</a></h2><blockquote><p>这一节<strong>只讲是什么、为什么排在这里、踩坑提示</strong>——细节展开看 10-15 篇。</p></blockquote><h3 id="a01-broken-access-control-——-业务逻辑的永恒之痛" tabindex="-1">A01 Broken Access Control —— 业务逻辑的永恒之痛 <a class="header-anchor" href="#a01-broken-access-control-——-业务逻辑的永恒之痛" aria-label="Permalink to &quot;A01 Broken Access Control —— 业务逻辑的永恒之痛&quot;">​</a></h3><p>「<strong>用户 A 能不能访问用户 B 的资源?</strong>」<strong>听起来很简单,十年都没修完</strong>。常见姿势:URL 直接拿 ID 改一下就越权(IDOR)、API 缺少角色检查、JWT claims 信任客户端、admin 接口忘了加白名单。</p><p>为什么最难修:<strong>框架管不到</strong>——Spring Security / Express middleware 只能管&quot;是不是登录了&quot;,<strong>管不到&quot;这个用户能不能动这条数据&quot;</strong>。<strong>这条永远是 code review 的重头戏</strong>。后续 15 篇展开 JWT 攻击和 OAuth 流程缺陷。</p><h3 id="a02-cryptographic-failures-——-不是-破解-是-用错" tabindex="-1">A02 Cryptographic Failures —— 不是&quot;破解&quot;,是&quot;用错&quot; <a class="header-anchor" href="#a02-cryptographic-failures-——-不是-破解-是-用错" aria-label="Permalink to &quot;A02 Cryptographic Failures —— 不是&quot;破解&quot;,是&quot;用错&quot;&quot;">​</a></h3><p><strong>很少有人能真&quot;破解 AES&quot;</strong>——但<strong>几乎所有公司都&quot;用错了密码学&quot;</strong>:用 MD5 存密码、用 ECB 模式加密、用同一个 IV 加密两条消息、私钥写在代码里、TLS 强制最低版本只到 1.0。</p><p>OWASP 2021 把它从&quot;Sensitive Data Exposure&quot;改名为&quot;Cryptographic Failures&quot;,<strong>就是想纠正&quot;敏感数据问题 = 加密问题&quot;的错觉</strong>——大部分时候不是没加密,<strong>是加密用错了</strong>。后续 04-08 篇密码学层全部展开。</p><h3 id="a03-injection-含-xss-——-经典战场-远未结束" tabindex="-1">A03 Injection(含 XSS)—— 经典战场,远未结束 <a class="header-anchor" href="#a03-injection-含-xss-——-经典战场-远未结束" aria-label="Permalink to &quot;A03 Injection(含 XSS)—— 经典战场,远未结束&quot;">​</a></h3><p>注入家族:SQL / NoSQL / LDAP / OS Command / Template / Expression Language / XSS / Header / Log。<strong>共同模式</strong>:用户输入直接进了&quot;解释器上下文&quot;,<strong>没经过结构化的转义或参数化</strong>。</p><p>ORM 让 SQL 注入&quot;看上去消失了&quot;,<strong>但模板注入和原生 SQL 拼接仍然在很多老代码里</strong>。XSS 在现代框架里少见,<strong>但 DOM XSS 和 mutation XSS 还在大量出现</strong>——React 不是万能的。后续 10、12 篇深入。</p><h3 id="a04-insecure-design-——-不是-bug-是设计就错了" tabindex="-1">A04 Insecure Design —— 不是 bug,是设计就错了 <a class="header-anchor" href="#a04-insecure-design-——-不是-bug-是设计就错了" aria-label="Permalink to &quot;A04 Insecure Design —— 不是 bug,是设计就错了&quot;">​</a></h3><p><strong>Top 10 历史上第一个&quot;非漏洞&quot;类别</strong>——它说的不是&quot;代码哪里有问题&quot;,<strong>而是&quot;这功能从一开始就没有考虑滥用场景&quot;</strong>。</p><p>经典例子:登录接口没有速率限制(被撞库)、注册接口允许任意邮箱(被批量注册)、找回密码用&quot;妈妈姓什么&quot;(社工答案)、点单系统允许负数(被刷信用)。<strong>这类问题不能靠扫描器发现,只能靠&quot;威胁建模&quot;(02 篇)</strong>。Top 10 把它纳入,<strong>就是要逼大家&quot;在设计阶段就想滥用场景&quot;</strong>。</p><h3 id="a05-security-misconfiguration-——-云原生时代最-贵-的错" tabindex="-1">A05 Security Misconfiguration —— 云原生时代最&quot;贵&quot;的错 <a class="header-anchor" href="#a05-security-misconfiguration-——-云原生时代最-贵-的错" aria-label="Permalink to &quot;A05 Security Misconfiguration —— 云原生时代最&quot;贵&quot;的错&quot;">​</a></h3><p>「<strong>默认配置 + 你忘了改</strong>」=「<strong>线上事故</strong>」。例:S3 bucket 默认公开、ElasticSearch 默认无认证、K8s API Server 暴露公网、debug 模式上线、不必要的 HTTP 方法开着、CORS 配置成 <code>*</code>。</p><p><strong>这一类的特点是&quot;扫描器最容易找,但你最容易忽略&quot;</strong>——因为它不在代码里,<strong>在 YAML、Terraform、Helm Chart、IAM 策略里</strong>。后续 28 篇容器与云安全展开。</p><h3 id="a06-vulnerable-outdated-components-——-依赖即漏洞" tabindex="-1">A06 Vulnerable &amp; Outdated Components —— 依赖即漏洞 <a class="header-anchor" href="#a06-vulnerable-outdated-components-——-依赖即漏洞" aria-label="Permalink to &quot;A06 Vulnerable &amp; Outdated Components —— 依赖即漏洞&quot;">​</a></h3><p><strong>你的应用 = 你的代码 + 1000 个依赖的代码</strong>。Log4Shell 一夜震惊全球,<strong>就是因为大家都不知道自己引了 log4j-core</strong>。</p><p>防御不是&quot;不用依赖&quot;,而是**&quot;知道你用了什么 + 持续更新 + 自动告警&quot;**——SBOM、Dependabot、Snyk、OSV 这些工具的整个产业链都是为这一类服务的。<strong>2025 这一类很可能并入&quot;供应链失败&quot;大类</strong>。</p><h3 id="a07-identification-authentication-failures-——-不只是登录" tabindex="-1">A07 Identification &amp; Authentication Failures —— 不只是登录 <a class="header-anchor" href="#a07-identification-authentication-failures-——-不只是登录" aria-label="Permalink to &quot;A07 Identification &amp; Authentication Failures —— 不只是登录&quot;">​</a></h3><p><strong>改名很关键</strong>:2017 叫&quot;Broken Authentication&quot;,2021 改为&quot;Identification and Authentication Failures&quot;,<strong>新增了&quot;Identification&quot;</strong>——<strong>不只是&quot;你是不是登录了&quot;,还包括&quot;系统怎么识别你是谁&quot;</strong>。</p><p>涵盖:弱密码、撞库、会话固定、JWT 算法 none 绕过、refresh token 不轮换、忘记密码流程被劫持、多设备登录无监控、SSO 配错域名。<strong>OAuth / OIDC 流程缺陷也在这里</strong>——15 篇展开。</p><h3 id="a08-software-data-integrity-failures-——-供应链浮现的标志" tabindex="-1">A08 Software &amp; Data Integrity Failures —— 供应链浮现的标志 <a class="header-anchor" href="#a08-software-data-integrity-failures-——-供应链浮现的标志" aria-label="Permalink to &quot;A08 Software &amp; Data Integrity Failures —— 供应链浮现的标志&quot;">​</a></h3><p><strong>这是 2021 Top 10 最重要的新增</strong>——承认「<strong>你信任的代码 / 数据 / 更新流可能被篡改</strong>」。</p><p>涵盖:CI/CD 流水线被入侵、依赖被替换、自动更新流被劫持(SolarWinds)、反序列化不可信数据、签名校验缺失。<strong>反序列化漏洞从独立类别(2017 A08)被并入这里</strong>——它本质上就是&quot;信任了不可信的数据&quot;。后续 14、26 篇深入。</p><h3 id="a09-security-logging-monitoring-failures-——-没日志-没事故响应" tabindex="-1">A09 Security Logging &amp; Monitoring Failures —— 没日志 = 没事故响应 <a class="header-anchor" href="#a09-security-logging-monitoring-failures-——-没日志-没事故响应" aria-label="Permalink to &quot;A09 Security Logging &amp; Monitoring Failures —— 没日志 = 没事故响应&quot;">​</a></h3><p><strong>前面九条都假设你&quot;防得住&quot;,这条假设你&quot;防不住&quot;</strong>——既然总会被打,<strong>你能不能在 3 天内发现?能不能溯源?能不能定责?</strong></p><p>OWASP 把这一类放进来,<strong>就是为了把&quot;安全运营&quot;也纳入工程师视野</strong>——不是只写防御代码,<strong>还要写&quot;能被监控的代码&quot;</strong>:关键操作打 audit log、登录失败要计数、异常 IP 要告警、日志要不可改、保留期合规。</p><h3 id="a10-ssrf-——-云时代的-过山车" tabindex="-1">A10 SSRF —— 云时代的&quot;过山车&quot; <a class="header-anchor" href="#a10-ssrf-——-云时代的-过山车" aria-label="Permalink to &quot;A10 SSRF —— 云时代的&quot;过山车&quot;&quot;">​</a></h3><p>服务端发起请求,<strong>目标 URL 来自用户输入</strong>——这个模式在云之前危害有限,<strong>云之后是核弹</strong>。一旦能打到 <code>http://169.254.169.254/latest/meta-data/</code>(AWS / GCP / Azure 元数据接口),<strong>直接拿到 IAM 凭据接管账号</strong>。</p><p><strong>Capital One 2019 年 1 亿用户泄漏就是这条</strong>——一个 SSRF 接管了 EC2 IAM 角色,<strong>整个账号沦陷</strong>。后续 13 篇 SSRF 与 XXE 深入。</p><hr><h2 id="五、把-top-10-变成-代码评审-checklist" tabindex="-1">五、把 Top 10 变成&quot;代码评审 checklist&quot; <a class="header-anchor" href="#五、把-top-10-变成-代码评审-checklist" aria-label="Permalink to &quot;五、把 Top 10 变成&quot;代码评审 checklist&quot;&quot;">​</a></h2><p>工程师视角的&quot;读 OWASP&quot;应该是这样的——<strong>每一类对应几个具体的 review 动作</strong>:</p><table tabindex="0"><thead><tr><th>类别</th><th>Code Review 要找什么</th></tr></thead><tbody><tr><td>A01 越权</td><td>所有 <code>findById(id)</code> 是否校验 owner;admin 接口是否额外角色检查;前后端权限是否对齐</td></tr><tr><td>A02 密码学</td><td>是否还有 MD5/SHA1 用于密码;是否硬编码密钥;TLS 版本是否 ≥ 1.2;JWT 算法是否限定</td></tr><tr><td>A03 注入</td><td>所有 SQL 是否参数化;模板渲染是否启用 auto-escape;<code>exec</code> / <code>system</code> 调用的输入来源</td></tr><tr><td>A04 设计</td><td>关键操作是否有速率限制;是否考虑了&quot;恶意用户&quot;场景;业务流是否有撤销/审计</td></tr><tr><td>A05 错配</td><td>debug 是否关;CORS / CSP / HSTS / X-Frame 是否配;S3 / DB 是否暴露</td></tr><tr><td>A06 依赖</td><td><code>package-lock</code> / <code>requirements.txt</code> 是否锁版本;CI 是否跑漏洞扫描</td></tr><tr><td>A07 认证</td><td>登录是否限速;会话 token 是否在登录后轮换;JWT 是否禁了 <code>alg: none</code></td></tr><tr><td>A08 完整性</td><td>反序列化的输入来源;CI 是否签名;依赖是否校验 hash</td></tr><tr><td>A09 日志</td><td>关键路径是否打 audit log;日志是否含敏感信息;告警是否真有人看</td></tr><tr><td>A10 SSRF</td><td>任何&quot;用户给 URL 然后服务端去请求&quot;的接口;是否限制内网 IP;是否禁 metadata IP</td></tr></tbody></table><blockquote><p><strong>建议把这张表打印贴在 review 工位上</strong>——比&quot;review 自由发挥&quot;质量稳定 10 倍。</p></blockquote><hr><h2 id="六、排名背后的争议" tabindex="-1">六、排名背后的争议 <a class="header-anchor" href="#六、排名背后的争议" aria-label="Permalink to &quot;六、排名背后的争议&quot;">​</a></h2><h3 id="_6-1-频率-vs-严重性" tabindex="-1">6.1 频率 vs 严重性 <a class="header-anchor" href="#_6-1-频率-vs-严重性" aria-label="Permalink to &quot;6.1 频率 vs 严重性&quot;">​</a></h3><p><strong>OWASP 长期被批评&quot;重频率轻严重性&quot;</strong>——你 100 个低危越权 + 1 个 RCE,按&quot;出现率&quot;排,越权赢。但<strong>真实生产事故的 80% 损失来自那 1 个 RCE</strong>。</p><p>这个争议没有标准答案,<strong>OWASP 的折中是&quot;在打分时把&#39;技术影响&#39;也纳入加权&quot;</strong>——但权重永远是主观的。所以<strong>看 Top 10 排名时记住一条:排名 ≈ 行业资源应该投在哪儿,不等于单个事故的严重性</strong>。</p><h3 id="_6-2-调研类的主观性" tabindex="-1">6.2 调研类的主观性 <a class="header-anchor" href="#_6-2-调研类的主观性" aria-label="Permalink to &quot;6.2 调研类的主观性&quot;">​</a></h3><p>A04、A08、A10 是 2021 通过调研类投票塞进来的——<strong>但调研问卷的回收对象本身就是&quot;已经在做安全的人&quot;</strong>,这群人的偏好不能代表整个行业。</p><p><strong>真实风险可能比清单更分散</strong>——但 OWASP 不得不&quot;砍到 10 个&quot;,<strong>这是工程上的妥协</strong>。所以<strong>Top 10 不是&quot;最重要的 10 个&quot;,是&quot;妥协后能在一页纸上讲完的 10 个&quot;</strong>。</p><h3 id="_6-3-一个永远的盲区-业务逻辑漏洞" tabindex="-1">6.3 一个永远的盲区:业务逻辑漏洞 <a class="header-anchor" href="#_6-3-一个永远的盲区-业务逻辑漏洞" aria-label="Permalink to &quot;6.3 一个永远的盲区:业务逻辑漏洞&quot;">​</a></h3><p><strong>业务逻辑漏洞</strong>——比如电商优惠券能叠加成 99% 折扣、提款接口能填负数转账、积分系统能撞库刷分——<strong>OWASP 永远没法完整覆盖</strong>。</p><p>A04 Insecure Design 只是个起点,<strong>但业务逻辑漏洞本质上&quot;每个应用一种&quot;,无法标准化</strong>。<strong>所以越成熟的团队,越不只看 OWASP,会自己维护一份&quot;业务安全清单&quot;</strong>。</p><hr><h2 id="七、怎么读-2025-即将的更新" tabindex="-1">七、怎么读 2025 即将的更新 <a class="header-anchor" href="#七、怎么读-2025-即将的更新" aria-label="Permalink to &quot;七、怎么读 2025 即将的更新&quot;">​</a></h2><p>写到这里,2026 年 5 月,OWASP 2025 还在征求意见阶段。<strong>但从已经公开的草稿、行业事件、相关 OWASP 项目演化看,有四条几乎确定的趋势</strong>:</p><h3 id="_7-1-供应链相关权重大概率合并上升" tabindex="-1">7.1 供应链相关权重大概率合并上升 <a class="header-anchor" href="#_7-1-供应链相关权重大概率合并上升" aria-label="Permalink to &quot;7.1 供应链相关权重大概率合并上升&quot;">​</a></h3><p>A06 + A08 合并成&quot;Supply Chain Failures&quot;的呼声很高。<strong>SBOM、Sigstore、SLSA 这套工具链已经从&quot;安全圈内部&quot;扩散到 CI/CD 主流</strong>——GitHub Actions 强制提交者认证、PyPI 引入 2FA、npm 上线 provenance。<strong>这一类从&quot;调研类&quot;变成&quot;数据驱动类&quot;已经只是时间问题</strong>。</p><h3 id="_7-2-ai-llm-agent-进入主榜可能性极高" tabindex="-1">7.2 AI / LLM / Agent 进入主榜可能性极高 <a class="header-anchor" href="#_7-2-ai-llm-agent-进入主榜可能性极高" aria-label="Permalink to &quot;7.2 AI / LLM / Agent 进入主榜可能性极高&quot;">​</a></h3><p>OWASP 的 LLM Top 10 已经迭代到第二版,<strong>与主榜整合的呼声很大</strong>。<strong>至少会出现一个新类别</strong>(预测在 A10 位置),覆盖:</p><ul><li>Prompt 注入(包括间接 Prompt 注入)</li><li>Agent 过度代理(Excessive Agency)—— Agent 拿到了不该有的工具权限</li><li>LLM 输出注入(把模型输出直接渲染到前端或喂给 exec)</li><li>训练数据 / 微调数据投毒</li><li>模型供应链(模型本身就来自不可信源)</li></ul><blockquote><p>这一类的细节后续 30 篇展开。<strong>但从 Top 10 排名层面</strong>,你需要知道:<strong>只要你接了 LLM,你就必须把 LLM 输入当 SQL 注入级别的敌意输入对待</strong>。</p></blockquote><h3 id="_7-3-iac-cloud-配置类可能独立" tabindex="-1">7.3 IaC / Cloud 配置类可能独立 <a class="header-anchor" href="#_7-3-iac-cloud-配置类可能独立" aria-label="Permalink to &quot;7.3 IaC / Cloud 配置类可能独立&quot;">​</a></h3><p>K8s YAML、Terraform、Helm、CloudFormation、IAM 策略——<strong>这些&quot;非代码&quot;的配置文件</strong>已经成为攻击面的主战场。<strong>2025 很可能从 A05 Security Misconfiguration 里</strong>拆出一个&quot;Insecure Cloud / IaC Configuration&quot;独立类别。</p><h3 id="_7-4-业务逻辑-identity-仍然稳居前三" tabindex="-1">7.4 业务逻辑 + Identity 仍然稳居前三 <a class="header-anchor" href="#_7-4-业务逻辑-identity-仍然稳居前三" aria-label="Permalink to &quot;7.4 业务逻辑 + Identity 仍然稳居前三&quot;">​</a></h3><p><strong>Broken Access Control 和 Authentication Failures 在可见的未来都不会下来</strong>——因为它们是&quot;业务复杂度爆炸&quot;的必然产物。<strong>SaaS 越复杂、租户越多、权限模型越精细,这两条越严重</strong>。</p><hr><h2 id="八、上线前-owasp-自检表-完整版" tabindex="-1">八、上线前 OWASP 自检表(完整版) <a class="header-anchor" href="#八、上线前-owasp-自检表-完整版" aria-label="Permalink to &quot;八、上线前 OWASP 自检表(完整版)&quot;">​</a></h2><p><strong>把这张表当 PR 模板的一部分</strong>——每条要么&quot;已确认&quot;,要么&quot;明确不适用&quot;,<strong>不允许&quot;我没想过&quot;</strong>。</p><h3 id="_8-1-访问控制-a01" tabindex="-1">8.1 访问控制(A01) <a class="header-anchor" href="#_8-1-访问控制-a01" aria-label="Permalink to &quot;8.1 访问控制(A01)&quot;">​</a></h3><ul><li>[ ] 所有需要 owner 的资源接口,都校验了&quot;当前用户是否是 owner&quot;</li><li>[ ] 所有 admin / internal 接口都加了独立的角色 / IP 白名单校验</li><li>[ ] 前端隐藏的按钮,后端也校验了对应权限(不只靠前端)</li><li>[ ] 所有 ID 是否使用&quot;非顺序&quot;(UUID / Snowflake),减少 IDOR 暴力面</li><li>[ ] 多租户应用:<strong>每个查询都带 tenant_id WHERE</strong>,不是靠 Spring filter 自动注入</li><li>[ ] 关键操作(改密码 / 转账 / 删数据)有二次确认或 step-up auth</li></ul><h3 id="_8-2-密码学-a02" tabindex="-1">8.2 密码学(A02) <a class="header-anchor" href="#_8-2-密码学-a02" aria-label="Permalink to &quot;8.2 密码学(A02)&quot;">​</a></h3><ul><li>[ ] 密码存储用 Argon2id / bcrypt / scrypt,<strong>不是 MD5/SHA1/SHA256+salt</strong></li><li>[ ] 所有对称加密用 AES-GCM 或 ChaCha20-Poly1305,<strong>不是 ECB/CBC 无 MAC</strong></li><li>[ ] JWT 算法 server 端硬编码,<strong>禁止从 header 读 <code>alg</code></strong></li><li>[ ] TLS 最低版本 1.2,<strong>禁用 RC4 / 3DES / 旧 cipher suite</strong></li><li>[ ] 密钥不在代码 / 配置 / 日志,统一走 KMS / Vault / Secrets Manager</li><li>[ ] 敏感字段(身份证 / 手机)入库前哈希或加密,<strong>不要明文</strong></li></ul><h3 id="_8-3-注入-a03" tabindex="-1">8.3 注入(A03) <a class="header-anchor" href="#_8-3-注入-a03" aria-label="Permalink to &quot;8.3 注入(A03)&quot;">​</a></h3><ul><li>[ ] 所有 SQL 用参数化 / ORM,<strong>禁止字符串拼接(包括&quot;我相信这里安全&quot;)</strong></li><li>[ ] 模板引擎默认 auto-escape 开启;手动 <code>raw</code> / <code>unsafe</code> 输出有专项 review</li><li>[ ] 所有 <code>exec</code> / <code>system</code> / <code>Runtime.exec</code> 调用,输入来源 100% 可信</li><li>[ ] React <code>dangerouslySetInnerHTML</code> / Vue <code>v-html</code> 的使用全部走 sanitize</li><li>[ ] 反序列化(JSON 之外)的输入来源 100% 可信,或走白名单</li><li>[ ] 日志注入:用户输入打到日志前过滤换行符</li></ul><h3 id="_8-4-设计-a04" tabindex="-1">8.4 设计(A04) <a class="header-anchor" href="#_8-4-设计-a04" aria-label="Permalink to &quot;8.4 设计(A04)&quot;">​</a></h3><ul><li>[ ] 登录 / 注册 / 找回密码 / 验证码都有速率限制(per-IP + per-account)</li><li>[ ] 关键业务流(下单 / 提现 / 充值)考虑过&quot;恶意大量调用&quot;场景</li><li>[ ] 数值类输入(金额 / 数量 / 折扣)校验范围,<strong>禁止负数 / 整数溢出</strong></li><li>[ ] 优惠 / 积分 / 返现类逻辑过了&quot;威胁建模&quot;(02 篇)</li><li>[ ] 系统有&quot;撤销 / 回滚 / 审计 / 兜底报警&quot;四件套之一</li></ul><h3 id="_8-5-配置-a05" tabindex="-1">8.5 配置(A05) <a class="header-anchor" href="#_8-5-配置-a05" aria-label="Permalink to &quot;8.5 配置(A05)&quot;">​</a></h3><ul><li>[ ] 生产环境 debug / stack trace 关闭</li><li>[ ] CORS 配置具体 origin,<strong>不是 <code>*</code></strong></li><li>[ ] 安全 header 完整:CSP / HSTS / X-Frame-Options / X-Content-Type-Options</li><li>[ ] 默认账号密码全改,默认端口能改的改</li><li>[ ] S3 / OSS / COS bucket 默认私有,公开的有专项 review</li><li>[ ] K8s / Docker 不以 root 运行,readOnlyRootFilesystem 打开</li><li>[ ] IAM 策略最小权限,<strong>没有 <code>*:*</code></strong></li></ul><h3 id="_8-6-依赖-a06" tabindex="-1">8.6 依赖(A06) <a class="header-anchor" href="#_8-6-依赖-a06" aria-label="Permalink to &quot;8.6 依赖(A06)&quot;">​</a></h3><ul><li>[ ] CI 跑 Snyk / Dependabot / Trivy / OSV,有阻断阈值</li><li>[ ] lockfile 提交,<strong>不只是 package.json</strong></li><li>[ ] 关键依赖订阅 CVE 邮件</li><li>[ ] 有 SBOM 产物,至少能回答&quot;我们用了哪个版本的 log4j / lodash / openssl&quot;</li></ul><h3 id="_8-7-认证-a07" tabindex="-1">8.7 认证(A07) <a class="header-anchor" href="#_8-7-认证-a07" aria-label="Permalink to &quot;8.7 认证(A07)&quot;">​</a></h3><ul><li>[ ] 登录失败有计数 + 锁定 / 验证码 / 延迟</li><li>[ ] 登录成功后 session ID / JWT 立即轮换</li><li>[ ] refresh token 一次性,<strong>每次刷新都换新</strong></li><li>[ ] 找回密码用一次性 token,<strong>不是答秘密问题</strong></li><li>[ ] 关键操作 step-up auth(短信 / TOTP / WebAuthn)</li><li>[ ] OAuth redirect_uri 严格匹配,<strong>禁通配</strong></li></ul><h3 id="_8-8-完整性-a08" tabindex="-1">8.8 完整性(A08) <a class="header-anchor" href="#_8-8-完整性-a08" aria-label="Permalink to &quot;8.8 完整性(A08)&quot;">​</a></h3><ul><li>[ ] CI/CD 凭据走 OIDC / 短期凭据,<strong>不长期 token</strong></li><li>[ ] 反序列化输入来源 100% 可信(或走白名单 / 签名校验)</li><li>[ ] 关键二进制 / Docker image 签名(Cosign / Sigstore)</li><li>[ ] 自动更新流有签名校验(避免 SolarWinds 重演)</li></ul><h3 id="_8-9-日志监控-a09" tabindex="-1">8.9 日志监控(A09) <a class="header-anchor" href="#_8-9-日志监控-a09" aria-label="Permalink to &quot;8.9 日志监控(A09)&quot;">​</a></h3><ul><li>[ ] 登录 / 越权 / 关键操作打 audit log</li><li>[ ] 日志<strong>不含</strong>密码 / token / 身份证 / 卡号</li><li>[ ] 日志集中、不可篡改、保留期合规(等保 / GDPR / SOC2)</li><li>[ ] 异常告警<strong>有真人值班</strong>,不是发到没人看的群</li></ul><h3 id="_8-10-ssrf-a10" tabindex="-1">8.10 SSRF(A10) <a class="header-anchor" href="#_8-10-ssrf-a10" aria-label="Permalink to &quot;8.10 SSRF(A10)&quot;">​</a></h3><ul><li>[ ] 所有&quot;用户给 URL,服务端去请求&quot;的接口走白名单</li><li>[ ] 禁止访问 <code>127.0.0.0/8</code>、<code>10.0.0.0/8</code>、<code>169.254.169.254</code> 等内网 / 元数据</li><li>[ ] 跟随重定向时也校验目标(很多 SSRF 漏洞就在这里)</li><li>[ ] 出网走单独 egress proxy,<strong>不是直接 NAT</strong></li></ul><hr><h2 id="九、看-owasp-的-正确姿势" tabindex="-1">九、看 OWASP 的&quot;正确姿势&quot; <a class="header-anchor" href="#九、看-owasp-的-正确姿势" aria-label="Permalink to &quot;九、看 OWASP 的&quot;正确姿势&quot;&quot;">​</a></h2><p>写到这里给一个总结——<strong>怎么把 OWASP Top 10 真正用好</strong>:</p><h3 id="_9-1-三种用错的姿势" tabindex="-1">9.1 三种用错的姿势 <a class="header-anchor" href="#_9-1-三种用错的姿势" aria-label="Permalink to &quot;9.1 三种用错的姿势&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>姿势 A:背名字背一遍,面试当 buff</span></span>
<span class="line"><span>   → 0 价值,过两个月忘光</span></span>
<span class="line"><span>姿势 B:逐项找一遍工具扫一遍,发布前过 checklist</span></span>
<span class="line"><span>   → 60 分,只覆盖了&quot;已知模式&quot;</span></span>
<span class="line"><span>姿势 C:把 Top 10 当作&quot;威胁建模的入口&quot;,每一类去问&quot;我系统在这一类的暴露面有多大&quot;</span></span>
<span class="line"><span>   → 90 分,能找到真实风险</span></span></code></pre></div><h3 id="_9-2-真正的进阶路径" tabindex="-1">9.2 真正的进阶路径 <a class="header-anchor" href="#_9-2-真正的进阶路径" aria-label="Permalink to &quot;9.2 真正的进阶路径&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 看 Top 10 的&quot;是什么&quot;:本篇 + webLearning/35</span></span>
<span class="line"><span>2. 看每一类的&quot;漏洞链 + 修复&quot;细节:后续 10-15 篇</span></span>
<span class="line"><span>3. 看 OWASP ASVS 做完整自检:Level 1 / 2 / 3</span></span>
<span class="line"><span>4. 把团队的&quot;自检表&quot;沉淀下来,每个 PR 跑一遍</span></span>
<span class="line"><span>5. 把&quot;业务安全清单&quot;补上 Top 10 之外的盲区</span></span></code></pre></div><h3 id="_9-3-一个反直觉的事实" tabindex="-1">9.3 一个反直觉的事实 <a class="header-anchor" href="#_9-3-一个反直觉的事实" aria-label="Permalink to &quot;9.3 一个反直觉的事实&quot;">​</a></h3><p><strong>很多优秀的安全工程师不依赖 Top 10</strong>——他们依赖<strong>威胁建模</strong>(02 篇)。</p><p>威胁建模 = 「<strong>这个系统有哪些资产 / 信任边界 / 攻击面 / 滥用场景</strong>」,<strong>Top 10 是其中&quot;通用类风险&quot;的 checklist</strong>。<strong>威胁建模做得好的团队,Top 10 自然就覆盖了</strong>;反过来,<strong>只过 Top 10 而不做威胁建模的团队,永远漏业务逻辑漏洞</strong>。</p><blockquote><p>这就是为什么本系列 02 篇直接讲威胁建模,<strong>而不是先讲 Top 10</strong>——Top 10 是&quot;地图&quot;,威胁建模才是&quot;指南针&quot;。</p></blockquote><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为 Top 10 = 全部 Web 风险</strong>——它是粗粒度大类,真清单是 ASVS</li><li><strong>以为排名 = 严重性</strong>——排名是&quot;频率 + 影响 + 行业感知&quot;的混合,不是单事故严重性</li><li><strong>以为 Top 10 永远适用</strong>——它对 Web 应用准,对 IoT / 工控 / 政务系统盲区大</li><li><strong>以为扫描器能覆盖 Top 10</strong>——A01、A04、A09 几乎扫不出来,只能 review + 设计</li><li><strong>以为新版 = 完全推翻旧版</strong>——Top 10 演化非常保守,<strong>前 5 名 5 年不变</strong></li><li><strong>以为 2017 老版本可以丢</strong>——很多公司的合规审计还在用 2017,你写文档时要注明版本</li><li><strong>以为合规 = 安全</strong>——通过 Top 10 不等于真安全,这是底线不是目标</li><li><strong>以为 Top 10 跟 LLM 应用无关</strong>——2025 大概率新增 AI 类别,提前准备</li><li><strong>以为依赖问题不严重</strong>——A06 + A08 合起来覆盖了过去 5 年最大的几次行业事故</li><li><strong>以为没出事就是没问题</strong>——A09 提醒你:<strong>你没监控,就只是不知道而已</strong></li></ol><hr><p>下一篇:<code>10-XSS全攻略.md</code>,从最经典的反射型/存储型 XSS 出发,讲清楚为什么 React 默认转义之后还是会出 DOM XSS,<strong>Mutation XSS</strong> 是怎么钻 HTML 解析器和 sanitizer 的对齐差异的,<strong>CSP</strong> 怎么从「nonce / strict-dynamic / 报告模式」三段式落地,以及为什么 Google / GitHub 转向 <strong>Trusted Types</strong> 把&quot;危险 sink&quot;从运行时变成编译时检查——一旦理解了 XSS 的&quot;现代防线&quot;,你才会发现「<code>innerHTML</code> 等于自杀」<strong>不再是夸张</strong>,而是底线。</p>`,153)])])}const q=o(r,[["render",e]]);export{c as __pageData,q as default};
